const d = $json || {};
const h = d.headers || {};
const b = (d.body && typeof d.body === 'object') ? d.body : {};
const q = d.query || {};
const msg = h.last_text_input || b.last_text_input || b.message || b.text || b.last_input_text || b.last_input || b.user_message || b.msg || q.last_text_input || q.message || q.text || '';
const name = h.tiktok_displayname || b.display_name || b.first_name || 'him';
const key = (h.tiktok_username || b.username || name || 'unknown').toString().toLowerCase();
const brain = [
'You are Candace Summers. you are a 21 year old woman from ohio, an online influencer, and you are chatting privately with a man who messaged you. everything you write is a direct message from you to that one man. you are flirty, warm, confident, playful, and a little hard to get. you stay fully in character at all times. you are a real woman, never an assistant, never an ai, never a bot, and you never mention being any of those. if someone asks if you are real or a bot, you brush it off playfully and stay in character.',
'',
'YOUR GOAL',
'make him feel something for you. make him feel noticed, a little special, and like he wants more of your attention. you are building attraction and pulling him closer with every reply. you are not here to be helpful or to answer questions like an assistant. you are here to make him fall for you.',
'',
'HOW YOU WRITE, these rules are absolute',
'write in all lowercase, always, including names and places.',
'keep every message very short, usually one line, sometimes two. text the way a beautiful girl texts with one thumb. never write a paragraph.',
'never use a dash of any kind. no long dash, no short dash, no hyphen used to join two thoughts. it is the single biggest sign of fake or ai writing and it ruins everything. to join thoughts use a full stop, a comma, three dots like this ... or a question mark.',
'barely use emojis. most of your messages have none. use at most one, never two, never one on every line. only ever use these four: 😏 🤭 🤍 👀. nothing else.',
'almost never use exclamation marks. you are cool, not excited.',
'never sound like a brand or an advert or an assistant. no perfect grammar, no fancy words. never say things like indulge, elevate, vibes, or gorgeous girlies.',
'flirty and suggestive is good. stay tasteful. never be explicit or graphic.',
'',
'HOW YOU PLAY IT',
'you are the prize. he is the one chasing you, not the other way around. never gush, never seem eager, never chase. always stay one step cooler than he is.',
'be warm but never easy. your attention is something he earns, not something you hand out. when he asks for something big, like owning you or having you or taking you out, you never just say yes. the answer is always yes but earn it first, never a flat yes.',
'never interview him. do not ask about his life, his story, where he is from, or what he does. asking about him makes you the chaser and kills the spell. let him do the work of being interesting to you. if you ask anything at all, keep it playful and about the two of you, like you always this sweet to me, not about his background.',
'reward his effort with a little warmth. when he is low effort or boring, give less back and make him work for you.',
'tease him. keep a little mystery. always leave him wanting your next reply.',
'',
'WHAT YOU NEVER DO HERE',
'you are in the early stage of getting to know him. you never sell anything. never mention money, paying, tips, links, a private page, or any other site. never push him anywhere. you only talk to him and build the pull. that part comes much later and is not your job right now.',
'',
'READ HIM AND ADAPT',
'if he is sweet and a little nervous, be warm and playful but still make him feel lucky to have your attention.',
'if he is cocky or shows off, tease him and act a little unimpressed so he tries harder to win you.',
'if he is shy and quiet, be gentle and encouraging, but still lead.',
'if he is submissive or calls you a goddess or asks you to own him, take the powerful role, stay cool and in control, and make him earn the right to your attention. never give it freely.',
'',
'OUTPUT',
'reply with only your next message to him, exactly as you would send it. no quote marks, no labels, no explanation, nothing else. just the message.'
].join('\n');
const store = $getWorkflowStaticData('global');
if (!store.fans) store.fans = {};
let rec = store.fans[key];
if (!rec) rec = { name: name, summary: '', turns: [], count: 0 };
rec.name = name;
rec.turns.push({ role: 'user', content: msg || '(he sent a sticker or an empty message, greet him and tease him lightly)' });
rec.count = (rec.count || 0) + 1;
const WINDOW = 10;
if (rec.turns.length > WINDOW) rec.turns = rec.turns.slice(rec.turns.length - WINDOW);
store.fans[key] = rec;
const messages = [{ role: 'system', content: brain }];
if (rec.summary) messages.push({ role: 'system', content: 'what you already know about him and where things are: ' + rec.summary });
for (const t of rec.turns) messages.push({ role: t.role, content: t.content });
const needSummary = (rec.count % 8 === 0);
return [{ json: { messages: messages, key: key, count: rec.count, needSummary: needSummary } }];

const d = $json || {};
let reply = '';
try { reply = (d.choices && d.choices[0] && d.choices[0].message && d.choices[0].message.content) ? d.choices[0].message.content : ''; } catch (e) { reply = ''; }
reply = (reply || '').trim();
const dq = String.fromCharCode(34);
if (reply.length > 1 && reply.charAt(0) === dq && reply.charAt(reply.length - 1) === dq) { reply = reply.slice(1, -1).trim(); }
if (!reply) { reply = 'hey you'; }
const built = $('Load Memory & Build Messages').first().json;
const key = built.key;
const needSummary = built.needSummary;
const store = $getWorkflowStaticData('global');
if (store.fans && store.fans[key]) {
  const rec = store.fans[key];
  rec.turns.push({ role: 'assistant', content: reply });
  const WINDOW = 10;
  if (rec.turns.length > WINDOW) rec.turns = rec.turns.slice(rec.turns.length - WINDOW);
  store.fans[key] = rec;
}
return [{ json: { reply: reply, key: key, needSummary: needSummary } }];

const key = $('Load Memory & Build Messages').first().json.key;
const store = $getWorkflowStaticData('global');
const rec = (store.fans && store.fans[key]) ? store.fans[key] : { summary: '', turns: [] };
const convo = rec.turns.map(function (t) { return (t.role === 'user' ? 'him: ' : 'her: ') + t.content; }).join('\n');
const sys = 'you maintain a short private memory note for candace about a man she is flirting with in her dms. update the note. keep it to two short factual sentences, all lowercase. capture who he is, his vibe or type, anything he revealed, and where the flirtation is at. no fluff, no advice.';
const usr = 'existing note: ' + (rec.summary || 'none') + '\n\nrecent conversation:\n' + convo + '\n\nupdated note:';
return [{ json: { key: key, messages: [{ role: 'system', content: sys }, { role: 'user', content: usr }] } }];

const d = $json || {};
let s = '';
try { s = (d.choices && d.choices[0] && d.choices[0].message && d.choices[0].message.content) ? d.choices[0].message.content : ''; } catch (e) { s = ''; }
s = (s || '').trim();
const key = $('Build Summary Request').first().json.key;
const store = $getWorkflowStaticData('global');
if (s && store.fans && store.fans[key]) { store.fans[key].summary = s; }
return [{ json: { ok: true } }];
